// // This module decrements the counter value by one on each rising edge of the clock signal 'clk' when the 'enable' signal is high. The counter should have an asynchronous reset 'rst_n' that resets the counter to zero when active low.
module up_counter_enable(
    input clk,
    input rst_n,
    input enable,
    output reg [9:0] count
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            count <= 10'b0000000000;
        else if (enable)
            count <= count + 1;
    end

endmodule
